INSERT INTO `Products` VALUES (101,1,'Mono Half-Cell Solar Panel Grade A 300W',0.00,'Grade A monocrystalline half-cell PV module for compact residential systems, solar generators, lighting kits, and small off-grid installations.','300W','Grade A Mono Half-Cell',NULL,'8 years product guarantee; 25 years performance design',NULL,NULL,NULL,'{\"power\": \"300W\", \"cell_grade\": \"Grade A\", \"technology\": \"Monocrystalline half-cell\", \"application\": \"residential, kit, off-grid\", \"module_type\": \"framed PV module\"}',1,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(102,1,'Mono Half-Cell Solar Panel Grade A 450W',0.00,'High-output monocrystalline PV module for home, commercial, and agricultural solar systems requiring strong generation density.','450W','Grade A Mono Half-Cell',NULL,'12 years product warranty; 25 years performance design',NULL,NULL,NULL,'{\"power\": \"450W\", \"technology\": \"Monocrystalline half-cell\", \"application\": \"home, commercial, agriculture\", \"module_type\": \"framed PV module\"}',1,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(103,1,'Mono Half-Cell Solar Panel Grade A 550W',0.00,'High-efficiency 550W solar panel for residential, commercial, and industrial PV arrays.','550W','Grade A Mono PERC / Half-Cell',NULL,'12 years product warranty; 25 years performance design',NULL,NULL,NULL,'{\"power\": \"550W\", \"efficiency\": \"21 percent class\", \"technology\": \"Monocrystalline half-cell\", \"application\": \"residential, commercial, industrial\", \"recommended_for\": \"large PV arrays\"}',1,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(104,1,'N-Type TOPCon Solar Panel 580W',0.00,'Premium N-type TOPCon PV module for higher yield, lower degradation, and commercial or utility-scale systems.','580W','N-Type TOPCon',NULL,'12 years product warranty; 25 years performance design',NULL,NULL,NULL,'{\"power\": \"580W\", \"advantages\": \"low degradation, high yield\", \"technology\": \"N-Type TOPCon\", \"applicati