-- BEGIN DEYE OFFICIAL INVERTER CATALOG
-- Generated from all official Deye inverter category pages, including pagination,
-- on 2026-06-29. Identical regional listings are consolidated. One Products row represents one product family; its model
-- variants and shared/custom specification values live in the normalized tables.

DROP TEMPORARY TABLE IF EXISTS `CatalogKitInverterAssignments`;
CREATE TEMPORARY TABLE `CatalogKitInverterAssignments` AS
SELECT kp.`id` AS `kit_product_id`, pm.`product_id`, pm.`model_code`
FROM `KitProducts` kp
JOIN `ProductModels` pm ON pm.`id`=kp.`product_model_id`
WHERE pm.`product_id` IN (203,206,207,209,210);

DELETE FROM `ProductSpecifications` WHERE `product_id` IN (203,206,207,209,210,2201,2202,2203,2204,2205,2206,2207,2208,2209,2210,2211,2212,2213,2214,2215,2216,2217,2218,2219,2220,2221,2222,2223,2224,2225,2226,2227,2228,2229,2301,2302,2303,2304,2305,2306,2307,2308,2309,2310,2311,2312,2313,2314,2315,2316,2317,2318,2319,2320,2321,2322,2323,2324,2325,2326,2401,2402,2403,2501,2502,2503,2504,2505,2506,2507,2508);
DELETE FROM `ProductModels` WHERE `product_id` IN (203,206,207,209,210,2201,2202,2203,2204,2205,2206,2207,2208,2209,2210,2211,2212,2213,2214,2215,2216,2217,2218,2219,2220,2221,2222,2223,2224,2225,2226,2227,2228,2229,2301,2302,2303,2304,2305,2306,2307,2308,2309,2310,2311,2312,2313,2314,2315,2316,2317,2318,2319,2320,2321,2322,2323,2324,2325,2326,2401,2402,2403,2501,2502,2503,2504,2505,2506,2507,2508);

-- Remove superseded inverter rows while retaining the two locally sourced
-- high-frequency inverter/chargers and the five kit-linked Deye family IDs.
DELETE pi FROM `ProductImages` pi
JOIN `Products` p ON p.`id`=pi.`product_id`
WHERE p.`category_id`=2 AND p.`id` NOT IN (201,202,203,206,207,209,210);
DELETE ps FROM `ProductSpecifications` ps
JOIN `Products` p ON p.`id`=ps.`product_id`
WHERE p.`category_id`=2 AND p.`id` NOT IN (201,202,203,206,207,209,210);
DELETE pm FROM `ProductModels` pm
JOIN `Products` p ON p.`id`=pm.`product_id`
WHERE p.`category_id`=2 AND p.`id` NOT IN (201,202,203,206,207,209,210);
DELETE FROM `Products` WHERE `category_id`=2 AND `id` NOT IN (201,202,203,206,207,209,210);

UPDATE `Categories` SET
  `name`='Hybrid Inverters',
  `description`='Deye single-phase and three-phase hybrid inverter families for low-voltage and high-voltage battery systems.',
  `slug`='hybrid-inverters'
WHERE `id`=2;

ON DUPLICATE KEY UPDATE
  `name`=VALUES(`name`), `description`=VALUES(`description`),
  `image_url`=VALUES(`image_url`), `slug`=VALUES(`slug`);

UPDATE `Products` SET `category_id`=23 WHERE `id` IN (201,202);

ON DUPLICATE KEY UPDATE
  `category_id`=VALUES(`category_id`), `name`=VALUES(`name`),
  `description`=VALUES(`description`), `wattage`=VALUES(`wattage`),
  `durability_rating`=VALUES(`durability_rating`), `battery_type`=VALUES(`battery_type`),
  `warranty_info`=VALUES(`warranty_info`), `image_url`=VALUES(`image_url`),
  `metadata`=VALUES(`metadata`), `is_featured`=0;



UPDATE `KitProducts` kp
JOIN `CatalogKitInverterAssignments` assignment ON assignment.`kit_product_id`=kp.`id`
JOIN `ProductModels` pm
  ON pm.`product_id`=assignment.`product_id`
 AND pm.`model_code`=assignment.`model_code`
SET kp.`product_model_id`=pm.`id`;

DROP TEMPORARY TABLE `CatalogKitInverterAssignments`;
-- END DEYE OFFICIAL INVERTER CATALOG

